import NumberBox from "~/components/public/numberBox";
import { mapActions } from "vuex";
export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
      link: [{ rel: "icon", type: "image/x-icon", href: this.$store.getters.favicon}],
    };
  },
  components: {
    NumberBox,
  },
  async asyncData({ $get, $post }) {
    let shopCartList = [];
    let totalAmount = 0;
    let totalNum = 0;
    let isIndeterminate = false;
    let checkoutCount = 0;
    let isDataNull = true;
    let res = await $get("cart/lists");
    if (res.code == 1) {
      shopCartList = res.data.lists;
      totalAmount = res.data.total_amount;
      totalNum = res.data.total_num;
      isIndeterminate = false;
      checkoutCount = 0;
      shopCartList.forEach((item, index) => {
        // 有一个选中就是true
        if (item.selected == 1 || item.selected == true) {
          checkoutCount++;
          item.selected = true;
        } else {
          item.selected = false;
        }
      });
      isIndeterminate =
        checkoutCount > 0 && checkoutCount < shopCartList.length;
      if (shopCartList.length > 0) {
        isDataNull = false;
      } else {
        isDataNull = true;
      }
    }
    return {
      shopCartList,
      totalAmount,
      totalNum,
      isIndeterminate,
      checkoutCount,
      isDataNull,
    };
  },
  data() {
    return {
      checkAll: false,
      isIndeterminate: false,
      checkoutCount: 0,
    };
  },
  mounted() {},
  computed: {
    isSelectedAll: {
      get() {
        if (this.shopCartList.length <= 0) {
          return false;
        }
        let index = this.shopCartList.findIndex((item) => item.selected == 0);

        if (index == -1) {
          return true;
        }

        return false;
      },
      set(newVal) {
        let cartId = this.shopCartList.map((item) => item.cart_id);

        this.changeSelected(cartId, newVal);
      },
    },
  },
  methods: {
    ...mapActions(["getPublicData"]),
    async getCartList() {
      let res = await this.$get("cart/lists");
      if (res.code == 1) {
        this.shopCartList = Object.assign([], res.data.lists);
        this.totalAmount = res.data.total_amount;
        this.totalNum = res.data.total_num;
        this.isIndeterminate = true;
        this.checkoutCount = 0;
        this.shopCartList.forEach((item, index) => {
          // 有一个选中就是true
          if (item.selected == 1 || item.selected == true) {
            this.checkoutCount++;
            item.selected = true;
          } else {
            item.selected = false;
          }
        });
        this.isIndeterminate =
          this.checkoutCount > 0 &&
          this.checkoutCount < this.shopCartList.length;
        if (this.shopCartList.length > 0) {
          this.isDataNull = false;
        } else {
          this.isDataNull = true;
        }
      }
    },
    handleCheckAllChange(e) {},
    onBoxClick(e, cartId) {
      this.changeSelected(cartId, e);
    },
    async changeSelected(id, selected) {
      let res = await this.$post("cart/selected", {
        cart_id: id,
        selected: selected,
      });
      if (res.code == 1) {
        this.getCartList();
      }
    },
    async changeShopCartCount(number, cartId) {
      // cart/change
      let res = await this.$post("cart/change", {
        cart_id: cartId,
        goods_num: number,
      });
      if (res.code == 1) {
        this.getCartList();
        this.getPublicData();
      }
    },
    async goodsDelete(cartId) {
      let res = await this.$post("cart/del", {
        cart_id: cartId,
      });
      if (res.code == 1) {
        this.getPublicData();
        this.getCartList();
        this.$message({
          message: "删除商品成功",
          type: "success",
        });
      }
    },
    deleteSelectedGoods() {
      let selectedGoodsArr = this.shopCartList.filter((item) => {
        return item.selected == 1 || item.selected == true;
      });
      if (selectedGoodsArr.length <= 0) {
        this.$message({
          message: "没有选择商品",
          type: "error",
        });
        return;
      }
      let cartIdArr = selectedGoodsArr.map((item) => item.cart_id);
      this.goodsDelete(cartIdArr);
    },
    toOrderBuy() {
      let { shopCartList } = this;
      let goods = [];
      shopCartList.forEach((item) => {
        if (item.selected) {
          goods.push({
            item_id: item.item_id,
            num: item.goods_num,
          });
        }
      });
      if (goods.length == 0)
        return this.$message({
          message: "您还没有选择商品哦",
        });
      let url =
        "/confirm_order?data=" +
        encodeURIComponent(JSON.stringify({ goods, type: "cart" }));
      this.$router.push(url);
    },
    toIndex() {
      this.$router.push("/");
    },
  },
};
